// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"bytes"
	"context"
	"encoding/json"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel, nil)
	require.NotNil(t, logger)
	assert.Equal(t, logrus.InfoLevel, logger.logLevel)
	assert.Nil(t, logger.output)
	assert.False(t, logger.useJSON)
}

func TestLogDecision(t *testing.T) {
	tests := []struct {
		name      string
		identity  identity.NumericIdentity
		policy    string
		verdict   string
		reason    string
		useJSON   bool
		expectLog bool
	}{
		{
			name:      "allow decision",
			identity:  identity.NumericIdentity(100),
			policy:    "test-policy",
			verdict:   "ALLOW",
			reason:    "matched ingress rule",
			useJSON:   false,
			expectLog: true,
		},
		{
			name:      "deny decision",
			identity:  identity.NumericIdentity(200),
			policy:    "deny-policy",
			verdict:   "DENY",
			reason:    "no matching ingress rules",
			useJSON:   false,
			expectLog: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			output := &bytes.Buffer{}
			logger := NewPolicyAuditLogger(logrus.DebugLevel, output)
			logger.SetJSONOutput(tt.useJSON)

			logger.LogDecision(tt.identity, tt.policy, tt.verdict, tt.reason)

			if tt.useJSON {
				// For JSON output, we expect JSON to be written to the output buffer
				// But since we're logging to the default logger, output may be empty
				// This is expected behavior
			} else {
				// For regular logging, the log entry should be created
				// but output depends on the logger configuration
			}
		})
	}
}

func TestLogDecisionWithJSON(t *testing.T) {
	output := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.DebugLevel, output)
	logger.SetJSONOutput(true)

	testIdentity := identity.NumericIdentity(42)
	testPolicy := "my-policy"
	testVerdict := "ALLOW"
	testReason := "test-reason"

	logger.LogDecision(testIdentity, testPolicy, testVerdict, testReason)

	// Verify JSON output was written
	if output.Len() > 0 {
		var entry map[string]interface{}
		err := json.Unmarshal(output.Bytes(), &entry)
		assert.NoError(t, err)
		assert.Equal(t, "policy_decision", entry["event_type"])
		assert.NotNil(t, entry["fields"])
	}
}

func TestLogEvaluation(t *testing.T) {
	tests := []struct {
		name       string
		policyKey  string
		result     string
		useJSON    bool
		expectLog  bool
	}{
		{
			name:      "evaluation success",
			policyKey: "policy-1",
			result:    "evaluation_complete",
			useJSON:   false,
			expectLog: true,
		},
		{
			name:      "evaluation error",
			policyKey: "policy-2",
			result:    "evaluation_error",
			useJSON:   false,
			expectLog: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			output := &bytes.Buffer{}
			logger := NewPolicyAuditLogger(logrus.DebugLevel, output)
			logger.SetJSONOutput(tt.useJSON)

			ctx := context.Background()
			logger.LogEvaluation(ctx, tt.policyKey, nil, tt.result)

			// Verify the logger was called (it should not panic)
			// Actual log output verification depends on logger configuration
		})
	}
}

func TestLogEvaluationWithJSON(t *testing.T) {
	output := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.DebugLevel, output)
	logger.SetJSONOutput(true)

	ctx := context.Background()
	testPolicyKey := "test-policy-key"
	testResult := "success"

	logger.LogEvaluation(ctx, testPolicyKey, nil, testResult)

	// Verify JSON output was written
	if output.Len() > 0 {
		var entry map[string]interface{}
		err := json.Unmarshal(output.Bytes(), &entry)
		assert.NoError(t, err)
		assert.Equal(t, "policy_evaluation", entry["event_type"])
		assert.NotNil(t, entry["fields"])
	}
}

func TestSetLogLevel(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel, nil)
	assert.Equal(t, logrus.InfoLevel, logger.logLevel)

	logger.SetLogLevel(logrus.DebugLevel)
	assert.Equal(t, logrus.DebugLevel, logger.logLevel)

	logger.SetLogLevel(logrus.WarnLevel)
	assert.Equal(t, logrus.WarnLevel, logger.logLevel)
}

func TestSetJSONOutput(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel, nil)
	assert.False(t, logger.useJSON)

	logger.SetJSONOutput(true)
	assert.True(t, logger.useJSON)

	logger.SetJSONOutput(false)
	assert.False(t, logger.useJSON)
}

func TestThreadSafety(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.DebugLevel, nil)

	// Run concurrent operations
	done := make(chan bool)
	for i := 0; i < 5; i++ {
		go func(id int) {
			logger.LogDecision(identity.NumericIdentity(id), "policy", "ALLOW", "test")
			logger.SetLogLevel(logrus.InfoLevel)
			logger.SetJSONOutput(true)
			done <- true
		}(i)
	}

	for i := 0; i < 5; i++ {
		<-done
	}
	// If we reach here without deadlock or panic, thread safety is working
}

func TestLogDecisionFields(t *testing.T) {
	output := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.DebugLevel, output)
	logger.SetJSONOutput(true)

	testIdentity := identity.NumericIdentity(999)
	testPolicy := "complex-policy"
	testVerdict := "DENY"
	testReason := "multiple reasons"

	logger.LogDecision(testIdentity, testPolicy, testVerdict, testReason)

	// Check that JSON output contains the expected fields
	if output.Len() > 0 {
		lines := bytes.Split(bytes.TrimSpace(output.Bytes()), []byte("\n"))
		for _, line := range lines {
			if len(line) == 0 {
				continue
			}
			var entry map[string]interface{}
			err := json.Unmarshal(line, &entry)
			if err != nil {
				continue
			}

			if entry["event_type"] == "policy_decision" {
				fields, ok := entry["fields"].(map[string]interface{})
				assert.True(t, ok, "fields should be a map")
				assert.NotNil(t, fields[logfields.Identity])
				assert.Equal(t, testPolicy, fields["policy"])
				assert.Equal(t, testVerdict, fields["verdict"])
				assert.Equal(t, testReason, fields[logfields.Reason])
			}
		}
	}
}

func TestLogEvaluationFields(t *testing.T) {
	output := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.DebugLevel, output)
	logger.SetJSONOutput(true)

	ctx := context.Background()
	testPolicyKey := "eval-policy-key"
	testResult := "completed"

	logger.LogEvaluation(ctx, testPolicyKey, nil, testResult)

	// Check that JSON output contains the expected fields
	if output.Len() > 0 {
		lines := bytes.Split(bytes.TrimSpace(output.Bytes()), []byte("\n"))
		for _, line := range lines {
			if len(line) == 0 {
				continue
			}
			var entry map[string]interface{}
			err := json.Unmarshal(line, &entry)
			if err != nil {
				continue
			}

			if entry["event_type"] == "policy_evaluation" {
				fields, ok := entry["fields"].(map[string]interface{})
				assert.True(t, ok, "fields should be a map")
				assert.NotNil(t, fields[logfields.PolicyKey])
				assert.Equal(t, testResult, fields["result"])
			}
		}
	}
}

func TestLogLevelControl(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.WarnLevel, nil)

	// Initially set to WarnLevel
	assert.Equal(t, logrus.WarnLevel, logger.logLevel)

	// Update to InfoLevel
	logger.SetLogLevel(logrus.InfoLevel)
	assert.Equal(t, logrus.InfoLevel, logger.logLevel)

	// Update to ErrorLevel
	logger.SetLogLevel(logrus.ErrorLevel)
	assert.Equal(t, logrus.ErrorLevel, logger.logLevel)
}

